    die "Usage: $0 <filename_or_directory> [--compress] [--checksum] [--list] [--restore <archive>]\n";
}

my $filename = $ARGV[0];
my $compress_flag = grep { $_ eq '--compress' } @ARGV;
my $checksum_flag = grep { $_ eq '--checksum' } @ARGV;
my $list_flag = grep { $_ eq '--list' } @ARGV;
my $restore_flag = 0;
my $restore_archive = '';

for my $i (0 .. $#ARGV) {
    if ($ARGV[$i] eq '--restore' && defined $ARGV[$i + 1]) {
        $restore_flag = 1;
        $restore_archive = $ARGV[$i + 1];
        last;
    }
}

# Validate that the file or directory exists
unless (-e $filename) {
    die "Error: '$filename' does not exist.\n";
}

# Sanitize filename to prevent command injection
if ($filename =~ /[;&|`\$\(\)\{\}\[\]!#~]/) {
    die "Error: Filename contains invalid characters.\n";
}

# Generate timestamp for backup naming
my $timestamp = strftime("%Y%m%d_%H%M%S", localtime);
my $basename = basename($filename);
my $backup_dir = "backups";

# Create backup directory if it doesn't exist
unless (-d $backup_dir) {
    mkdir $backup_dir or die "Error: Cannot create backup directory '$backup_dir': $!\n";
    print "Created backup directory: $backup_dir\n";
}

# --- Function: Create compressed tar archive ---
sub create_backup {
    my ($source) = @_;
    my $archive_name = "$backup_dir/${basename}_backup_${timestamp}.tar.gz";

    print "Creating backup of '$source'...\n";

    # Use system() for command execution with proper error handling
    my $tar_cmd = "tar -czf \Q$archive_name\E \Q$source\E";
    print "Executing: $tar_cmd\n";

    my $exit_code = system($tar_cmd);

    if ($exit_code == 0) {
        print "Backup created successfully: $archive_name\n";

        # Get file size using backticks
        my $size = `du -h \Q$archive_name\E`;
        chomp $size;
        print "Archive size: $size\n";

        return $archive_name;
    } else {
        my $signal = $exit_code & 127;
        my $return_val = $exit_code >> 8;
        die "Error: tar command failed with exit code $return_val (signal: $signal)\n";
    }
}

# --- Function: Generate checksum for verification ---
sub generate_checksum {
    my ($archive) = @_;

    print "Generating MD5 checksum for '$archive'...\n";

    # Use backticks to capture command output
    my $checksum_output;
    if (-e "/usr/bin/md5sum") {
        $checksum_output = `md5sum \Q$archive\E 2>&1`;
    } elsif (-e "/sbin/md5" || -e "/usr/bin/md5") {
        $checksum_output = `md5 \Q$archive\E 2>&1`;
    } else {
        warn "Warning: md5sum/md5 not found. Skipping checksum.\n";
        return;
    }

    if ($? == 0) {
        chomp $checksum_output;
        print "Checksum: $checksum_output\n";

        # Save checksum to a file
        my $checksum_file = "${archive}.md5";
        open(my $fh, '>', $checksum_file) or warn "Cannot write checksum file: $!\n";
        if ($fh) {
            print $fh "$checksum_output\n";
            close $fh;
            print "Checksum saved to: $checksum_file\n";
        }
    } else {
        warn "Warning: Checksum generation failed.\n";
    }
}

# --- Function: List contents of an archive ---
sub list_archive_contents {
    my ($archive) = @_;

    unless ($archive =~ /\.tar\.gz$/ || $archive =~ /\.tgz$/) {
        # Try to find the latest backup
        my @backups = glob("$backup_dir/${basename}_backup_*.tar.gz");
        if (@backups) {
            $archive = $backups[-1];
            print "Using latest backup: $archive\n";
        } else {
            die "Error: No backup archives found for '$basename'.\n";
