        print "-" x 60, "\n";
        print "Total entries: " . scalar(@files) . "\n";
    } else {
        die "Error: Failed to list archive contents.\n";
    }
}

# --- Function: Restore from archive ---
sub restore_backup {
    my ($archive, $dest) = @_;
    $dest //= "restored_${timestamp}";

    unless (-e $archive) {
        die "Error: Archive '$archive' not found.\n";
    }

    print "Restoring from '$archive' to '$dest/'...\n";

    mkdir $dest or die "Error: Cannot create restore directory '$dest': $!\n";

    my $exit_code = system("tar -xzf \Q$archive\E -C \Q$dest\E");

    if ($exit_code == 0) {
        print "Restore completed successfully to: $dest/\n";

        # List restored files using backticks
        my $restored_files = `ls -la \Q$dest\E 2>&1`;
        print "Restored contents:\n$restored_files\n";
    } else {
        die "Error: Restore failed with exit code " . ($exit_code >> 8) . "\n";
    }
}

# --- Function: Verify backup integrity ---
sub verify_backup {
    my ($archive) = @_;

    print "Verifying backup integrity of '$archive'...\n";

    # Test archive integrity using system()
    my $exit_code = system("tar -tzf \Q$archive\E > /dev/null 2>&1");

    if ($exit_code == 0) {
        print "Verification PASSED: Archive is intact.\n";

        # Check if checksum file exists and verify
        my $checksum_file = "${archive}.md5";
        if (-e $checksum_file) {
            if (-e "/usr/bin/md5sum") {
                my $verify_result = `md5sum -c \Q$checksum_file\E 2>&1`;
                if ($? == 0) {
                    print "Checksum verification PASSED.\n";
                } else {
                    warn "Warning: Checksum verification FAILED!\n";
                    print "Details: $verify_result\n";
                }
            }
        }
        return 1;
    } else {
        warn "Verification FAILED: Archive may be corrupted!\n";
        return 0;
    }
}

# --- Function: Clean old backups ---
sub clean_old_backups {
    my ($keep_count) = @_;
    $keep_count //= 5;

    print "Cleaning old backups (keeping last $keep_count)...\n";

    # Use backticks to find backup files sorted by time
    my $find_output = `ls -1t $backup_dir/${basename}_backup_*.tar.gz 2>/dev/null`;

    if ($? != 0 || !$find_output) {
        print "No old backups found to clean.\n";
        return;
    }

    my @backups = split /\n/, $find_output;

    if (scalar @backups <= $keep_count) {
        print "Only " . scalar(@backups) . " backup(s) found. Nothing to clean.\n";
        return;
    }

    my @to_delete = @backups[$keep_count .. $#backups];

    for my $old_backup (@to_delete) {
        chomp $old_backup;
        print "Removing old backup: $old_backup\n";
        my $exit_code = system("rm -f \Q$old_backup\E \Q${old_backup}.md5\E");
        if ($exit_code != 0) {
            warn "Warning: Failed to remove '$old_backup'\n";
        }
    }

    print "Cleanup complete. Removed " . scalar(@to_delete) . " old backup(s).\n";
}

